#include<bits/stdc++.h>
using namespace std;

char c[100001],a[11];

int main()
{
	int len1,len2,i,j,ans=0,s=0,cnt=0,maxn;
	scanf("%s",a);
	len1=strlen(a);
    int p=0;
	while(~scanf("%s",c))
	{
        p++;
		int flag=1;
		len2=strlen(c);
		if(len1==len2)
		{
			for(j=0;j<=len2-1;j++)
			{
				if(a[j]==c[j]||a[j]+32==c[j])
				{
					flag=1;
				}
				else
				{
					flag=0;
					break;
				}
			}
			if(flag==1)
			{
				ans++;
				if(cnt==0&&ans==1)
				{
					s=0;
					maxn=0;
				}
				else if(ans==1)
				{
					s=cnt+1;
					maxn=p;
				}
			}
		}
		cnt+=len2+1;
	}
	if(ans==0)
	{
		printf("-1");
		return 0;
	}
	printf("%d",ans);
	printf(" %d\n",maxn);
	return 0;
}
